#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    char *days[] = {"Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"};
    printf("%s\n", days[(n - 1) % 7]);
    return 0;
}

